import{_ as a,o as e,c as d,a2 as r}from"./chunks/framework.Cr-Z7ngm.js";const u=JSON.parse('{"title":"DDA自动扣款授权","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"deposit/dda-authorization.md","filePath":"zh-CN/deposit/dda-authorization.md"}'),o={name:"deposit/dda-authorization.md"};function i(l,t,n,h,p,s){return e(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="dda自动扣款授权" tabindex="-1">DDA自动扣款授权 <a class="header-anchor" href="#dda自动扣款授权" aria-label="Permalink to &quot;DDA自动扣款授权&quot;">​</a></h1><p>DDA（Direct Debit Authorisation）是新加坡银行与长桥证券合作的授权转账服务。将银行账户与长桥账户绑定后，可直接从长桥 App 发起新元入金，无需上传入金凭证。</p><p>注意：DDA 是新加坡账户服务，与香港账户的 eDDA（基于 FPS 转数快系统）是不同的服务。</p><table tabindex="0"><thead><tr><th>项目</th><th>说明</th></tr></thead><tbody><tr><td>支持币种</td><td>新加坡元（SGD）</td></tr><tr><td>到账时间</td><td>实时到账</td></tr><tr><td>手续费</td><td>免费</td></tr></tbody></table><h2 id="第一步-完成-dda-授权" tabindex="-1">第一步：完成 DDA 授权 <a class="header-anchor" href="#第一步-完成-dda-授权" aria-label="Permalink to &quot;第一步：完成 DDA 授权&quot;">​</a></h2><ol><li>打开长桥 App，进入<strong>资产 → 全部功能 → 存入资金 → SGD → DDA</strong>，按页面指引发起授权</li><li>确认银行端的证件信息与长桥端一致（不一致可在 App 的 DDA 授权页面更新证件）</li><li>授权时需<strong>完整阅读条款并划到底端</strong>，才能点击「Submit」提交（中途取消会导致授权失败）</li><li>等待授权结果通知</li></ol><h2 id="第二步-发起入金" tabindex="-1">第二步：发起入金 <a class="header-anchor" href="#第二步-发起入金" aria-label="Permalink to &quot;第二步：发起入金&quot;">​</a></h2><p>授权成功后，在长桥 App 的 DDA 入金页面输入入金金额，点击提交即可。无需上传入金凭证。</p><h2 id="解除-dda-授权" tabindex="-1">解除 DDA 授权 <a class="header-anchor" href="#解除-dda-授权" aria-label="Permalink to &quot;解除 DDA 授权&quot;">​</a></h2><p>解除授权需在长桥 App 和银行端<strong>双向操作</strong>：</p><ol><li>在长桥 App 入金页面删除该银行账户</li><li>在银行端操作解除 DDA 绑定</li></ol><blockquote><p>仅操作一端不会彻底解除：仅在 App 删除不会解除银行端授权；仅在银行端解除，App 不会自动更新，继续入金会显示失败。</p></blockquote><h2 id="常见授权失败原因" tabindex="-1">常见授权失败原因 <a class="header-anchor" href="#常见授权失败原因" aria-label="Permalink to &quot;常见授权失败原因&quot;">​</a></h2><table tabindex="0"><thead><tr><th>错误码</th><th>含义</th></tr></thead><tbody><tr><td>1209（Refer to your payer/payee）</td><td>银行账户余额或额度不足</td></tr><tr><td>1100（Other reason）</td><td>曾在银行端删除 DDA 绑定，需联系客服关闭旧记录后重新授权</td></tr><tr><td>ID number verification failed</td><td>长桥注册的身份证号与银行端不一致</td></tr><tr><td>BA3002（Consent not given）</td><td>授权页面条款未完整阅读即取消，需重新操作并完整阅读后提交</td></tr></tbody></table><h2 id="出金限制与账户信息一致性" tabindex="-1">出金限制与账户信息一致性 <a class="header-anchor" href="#出金限制与账户信息一致性" aria-label="Permalink to &quot;出金限制与账户信息一致性&quot;">​</a></h2><ul><li>DDA 不支持出金</li><li>银行端证件信息需与长桥开户信息一致</li></ul>',16)])])}const c=a(o,[["render",i]]);export{u as __pageData,c as default};
